345: func toScaleCreateValidation(f rest.ValidateObjectFunc) rest.ValidateObjectFunc {
346: 	return func(ctx context.Context, obj runtime.Object) error {
347: 		scale, err := scaleFromDeployment(obj.(*apps.Deployment))
